// CineSrc Movie Online Stream Provider
// Extracts streaming sources from cinesrc.st using native RSA-OAEP + AES-256-GCM encryption.

var BASE_URL = "https://cinesrc.st";
var UA = "Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/137.0.0.0 Mobile Safari/537.36";
var TOKEN_URL = "https://script.google.com/macros/s/AKfycbw_Q_5IHAiAmEABUh0QiqDUGzrHtTwkmbZcWhXM3ixH4IiukUK5wfDTQ5Sjj6EPwbRd/exec";

var RSA_PUBLIC_KEY_PEM = "-----BEGIN PUBLIC KEY-----\n" +
  "MIGfMA0GCSqGSIb3DQEBAQUAA4GNADCBiQKBgQCFplzWaLwhwOrmKuhe6Vghq4RU\n" +
  "NBjis9AUEl9Vw6r3CHz8aQGncnNgQ0t1oChO7I7EVs2oKcOrBNfhg+8aP4gURUoU\n" +
  "Xuk9M8M7OdeVvB2rTxiYIX+mvoslyTuAVRTWTvL5qQu9tZ84PfBCd6vFxku20TmF\n" +
  "MYYm2zpuXzCI4mmBewIDAQAB\n" +
  "-----END PUBLIC KEY-----";

var AES_DECRYPT_KEY_B64 = "JWmlRlgGKC3MLQihZMqx/hW276z1FolQ8QRePYWhn/E=";

var SERVER_LIST = ["nebula", "storm", "frost", "breeze", "rain", "mist"];

// Helper: Convert WordArray to raw byte array
function waToBytes(wa) {
  var hex = wa.toString(CryptoJS.enc.Hex);
  var out = [];
  for (var i = 0; i < hex.length; i += 2) {
    out.push(parseInt(hex.substr(i, 2), 16));
  }
  return out;
}

// Helper: Convert raw byte array to WordArray
function bytesToWA(bytes) {
  var hex = "";
  for (var i = 0; i < bytes.length; i++) {
    var s = bytes[i].toString(16);
    if (s.length < 2) s = "0" + s;
    hex += s;
  }
  return CryptoJS.enc.Hex.parse(hex);
}

// ─── HTTP helpers ────────────────────────────────────────────────────────────

async function fetchText(url, opts) {
  var resp = await fetch(url, Object.assign({ headers: { "User-Agent": UA } }, opts || {}));
  return $toString(resp.body, 0);
}

async function fetchJSON(url, opts) {
  var text = await fetchText(url, opts);
  return JSON.parse(text);
}

// ─── Provider ────────────────────────────────────────────────────────────────

class Provider {

  getSettings() {
    return { episodeServers: SERVER_LIST.map(function(s) { return s.charAt(0).toUpperCase() + s.slice(1); }) };
  }

  async search(opts) {
    var media = opts.media;
    if (!media || !media.id) return [];

    var mediaType = (media.mediaType === "tv") ? "tv" : "movie";
    var embedPath = "/embed/" + mediaType + "/" + media.id;

    return [{
      id: String(media.id),
      title: media.title || "Unknown",
      url: BASE_URL + embedPath,
      mediaType: mediaType,
    }];
  }

  async findEpisodes(id) {
    // For TV shows, we return an empty array as Goji will pass season/episode info
    // down to the findEpisodeServer method.
    return [];
  }

  async findMovieSources(id) {
    return this._extractSources(id, "movie", null, null);
  }

  async findEpisodeServer(episode, server) {
    var serverName = (server || "nebula").toLowerCase();
    var m = (episode.title || "").match(/S(\d+)\s*E(\d+)/i);
    var season = m ? m[1] : "1";
    var epNum = m ? m[2] : String(episode.number || 1);

    // The episode ID contains the TMDB ID
    var tmdbId = episode.id.replace(/^.*?(\d+).*$/, "$1");

    var results = await this._extractSources(tmdbId, "tv", season, epNum, serverName);
    return results && results.length > 0 ? results[0] : null;
  }

  async _extractSources(tmdbId, contentType, season, episode, serverName) {
    serverName = serverName || "nebula";

    // Build embed URL
    var embedPath = "/embed/" + (contentType === "tv" ? "tv" : "movie") + "/" + tmdbId;
    if (contentType === "tv" && season && episode) {
      embedPath += "?s=" + season + "&e=" + episode;
    }
    var embedUrl = BASE_URL + embedPath;
    var path = embedPath.split("?")[0];

    try {
      // Step 1: Get next-action tokens
      console.log("[CineSrc] Fetching action tokens...");
      var tokenData = await fetchJSON(TOKEN_URL);
      var actionTokens = tokenData.tokens;
      if (!actionTokens || actionTokens.length === 0) {
        console.error("[CineSrc] No action tokens received");
        return [];
      }

      // Step 2: Get signature token
      console.log("[CineSrc] Fetching signature...");
      var sigResponse = await fetchJSON(BASE_URL + "/api/signature", {
        headers: { "Referer": BASE_URL, "User-Agent": UA },
      });
      var token = sigResponse.token;
      if (!token) {
        console.error("[CineSrc] No signature token received");
        return [];
      }

      // Step 3: Build encrypted payload
      var encryptedBlob = this._buildEncryptedPayload(token, path, embedUrl);

      // Step 4: Prepare request and try action tokens
      var cType = contentType === "tv" ? "show" : "movie";
      var seasonVal = season || "$undefined";
      var episodeVal = episode || "$undefined";
      var requestPayload = [tmdbId, cType, seasonVal, episodeVal, encryptedBlob, serverName];

      var responseText = "";
      for (var i = 0; i < actionTokens.length; i++) {
        console.log("[CineSrc] Trying action token " + (i + 1) + "/" + actionTokens.length);
        responseText = await fetchText(embedUrl, {
          method: "POST",
          body: JSON.stringify(requestPayload),
          headers: {
            "Accept": "text/x-component",
            "next-action": actionTokens[i],
            "Content-Type": "text/plain;charset=UTF-8",
            "Referer": BASE_URL,
            "User-Agent": UA,
          },
        });
        if (responseText.indexOf("Server action") === -1) break;
      }

      if (!responseText || responseText.indexOf("Server action") !== -1) {
        console.error("[CineSrc] All action tokens failed");
        return [];
      }

      // Step 5: Extract and decrypt the response
      var lines = responseText.split("\n");
      if (lines.length < 2) {
        console.error("[CineSrc] Unexpected response format");
        return [];
      }

      var encryptedLine = lines[1];
      var encryptedPayload = encryptedLine.substring(2).replace(/^"|"$/g, "");

      var payloadParts = encryptedPayload.split(".");
      if (payloadParts.length < 3) {
        console.error("[CineSrc] Invalid encrypted payload format");
        return [];
      }

      var ivB64 = payloadParts[1];
      var ciphertextB64 = payloadParts[2];

      // Decrypt using native AES-256-GCM
      var decryptKey = CryptoJS.enc.Base64.parse(AES_DECRYPT_KEY_B64);
      var ivWA = CryptoJS.enc.Base64.parse(ivB64);
      var ciphertextWA = CryptoJS.enc.Base64.parse(ciphertextB64);

      var decrypted = CryptoJS.AES.decryptGCM(ciphertextWA, decryptKey, ivWA);
      var plaintext = decrypted.toString(CryptoJS.enc.Utf8);
      var streamingData = JSON.parse(plaintext);

      // Step 6: Build video sources
      var videoSources = [];
      var urlList = streamingData.url || streamingData.sources || [];

      for (var j = 0; j < urlList.length; j++) {
        var src = urlList[j];
        var srcUrl = src.url || src.file || "";
        if (!srcUrl) continue;

        var subtitles = [];
        if (src.subtitles) {
          for (var k = 0; k < src.subtitles.length; k++) {
            var sub = src.subtitles[k];
            subtitles.push({
              id: sub.label || ("sub-" + k),
              url: sub.file || sub.url || "",
              language: sub.label || "Unknown",
              isDefault: k === 0,
            });
          }
        }

        videoSources.push({
          url: srcUrl,
          type: srcUrl.indexOf(".mp4") !== -1 ? "mp4" : "m3u8",
          quality: src.quality || "auto",
          subtitles: subtitles,
        });
      }

      var displayName = serverName.charAt(0).toUpperCase() + serverName.slice(1);
      return [{
        server: displayName,
        headers: { "Referer": BASE_URL, "User-Agent": UA },
        videoSources: videoSources,
      }];

    } catch (e) {
      console.error("[CineSrc] Extraction failed:", e);
      return [];
    }
  }

  _buildEncryptedPayload(signatureToken, path, embedUrl) {
    // Generate secure random parameters using native Go crypto bindings
    var nonceWA = CryptoJS.randomBytes(16);
    var ivWA = CryptoJS.randomBytes(12);
    var aesKeyWA = CryptoJS.randomBytes(32);

    var timestamp = new Date().toISOString().replace("+00:00", "Z");

    var fingerprint = {
      tz: "Asia/Calcutta",
      lang: "en-GB",
      langs: "en-GB,en-US,en",
      pf: "Linux armv81",
      cm: true,
      dpr: 2,
      sw: 360,
      sh: 806,
      cd: 24,
      cvs: "6398717e3beb0e320556d5fb2077d04aaae6041ca9f2e8e6a2e912a156849ee1",
      wgl: "ANGLE (ARM, Mali-G57 MC2, OpenGL ES 3.2)|Google Inc. (ARM)",
      jit: "0.5999999046325684,0.9000000953674316,0.9000000953674316,0.5999999046325684,0.2999997138977051",
    };

    var nonceB64 = nonceWA.toString();
    var payload = {
      _r: 1.1,
      _k: timestamp,
      _m: UA,
      _n1l: "i3Dguw==",
      _x: nonceB64,
      _q: nonceB64,
      _j: signatureToken,
      _n25: "mtD6yA==",
      _w: path,
      _f: fingerprint,
    };

    // Flatten payload to key/value list
    var payloadArray = [];
    var keys = Object.keys(payload);
    for (var i = 0; i < keys.length; i++) {
      payloadArray.push(keys[i]);
      payloadArray.push(payload[keys[i]]);
    }
    var plaintextStr = JSON.stringify(payloadArray);

    // Parse to WordArray
    var plaintextWA = CryptoJS.enc.Utf8.parse(plaintextStr);

    // XOR plaintext with AES key
    var plaintextBytes = waToBytes(plaintextWA);
    var aesKeyBytes = waToBytes(aesKeyWA);
    var xoredBytes = new Array(plaintextBytes.length);
    for (var i = 0; i < plaintextBytes.length; i++) {
      xoredBytes[i] = plaintextBytes[i] ^ aesKeyBytes[i % aesKeyBytes.length];
    }
    var xoredWA = bytesToWA(xoredBytes);

    // Encrypt payload using native AES-256-GCM
    var aesCiphertextWA = CryptoJS.AES.encryptGCM(xoredWA, aesKeyWA, ivWA);

    // Encrypt AES key using native RSA-OAEP
    var rsaEncryptedKeyB64 = CryptoJS.RSA.encryptOAEP(aesKeyWA, RSA_PUBLIC_KEY_PEM);

    // Build the final encrypted blob
    var encryptedKeyB64 = rsaEncryptedKeyB64;
    var ivB64 = ivWA.toString();
    var ciphertextB64 = aesCiphertextWA.toString();

    return "v1.1~" + encryptedKeyB64 + "~" + ivB64 + "~" + ciphertextB64;
  }
}
